import{_ as e,o as a,c as r,a5 as l}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"UPS电源软件开发 — 学习资源列表","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"UPS电源软件开发 — 学习资源列表","tags":["power-electronics"],"status":"learning","summary":"| 书名 | 作者 | 说明 | 优先级 | |------|------|------|--------| | 《电力电子技术》（第6版） | 王兆安、刘进军 | 国内电力电子经典教材，覆盖整流、逆变、斩波、变频四大变换 | 必读 | | 《Power Electronics: Converters, Applica"},"headers":[],"relativePath":"content/power/RESOURCES.md","filePath":"content/power/RESOURCES.md","lastUpdated":null}'),i={name:"content/power/RESOURCES.md"};function d(n,t,o,h,s,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="ups电源软件开发-—-学习资源列表" tabindex="-1">UPS电源软件开发 — 学习资源列表 <a class="header-anchor" href="#ups电源软件开发-—-学习资源列表" aria-label="Permalink to &quot;UPS电源软件开发 — 学习资源列表&quot;">​</a></h1><h2 id="一、核心书籍-必读" tabindex="-1">一、核心书籍（必读） <a class="header-anchor" href="#一、核心书籍-必读" aria-label="Permalink to &quot;一、核心书籍（必读）&quot;">​</a></h2><h3 id="电力电子基础" tabindex="-1">电力电子基础 <a class="header-anchor" href="#电力电子基础" aria-label="Permalink to &quot;电力电子基础&quot;">​</a></h3><table tabindex="0"><thead><tr><th>书名</th><th>作者</th><th>说明</th><th>优先级</th></tr></thead><tbody><tr><td>《电力电子技术》（第6版）</td><td>王兆安、刘进军</td><td>国内电力电子经典教材，覆盖整流、逆变、斩波、变频四大变换</td><td>必读</td></tr><tr><td>《Power Electronics: Converters, Applications, and Design》</td><td>Ned Mohan</td><td>国际经典，英文原版更佳，理论推导严谨</td><td>推荐</td></tr><tr><td>《开关电源设计》</td><td>Abraham I. Pressman</td><td>实用性强，涵盖拓扑选择、磁件设计、控制环路</td><td>推荐</td></tr></tbody></table><h3 id="数字控制与嵌入式" tabindex="-1">数字控制与嵌入式 <a class="header-anchor" href="#数字控制与嵌入式" aria-label="Permalink to &quot;数字控制与嵌入式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>书名</th><th>作者</th><th>说明</th><th>优先级</th></tr></thead><tbody><tr><td>《嵌入式数字控制系统：基于C和Python编程实现》</td><td>Cem Unsalan 等</td><td>Python原型验证→C语言MCU实现→系统整合，三阶段教学法</td><td>必读</td></tr><tr><td>《微控制器原理及应用——基于TI C2000实时微控制器》</td><td>蔡逢煌 等</td><td>C2000是UPS/DPS领域主力MCU，本书覆盖ePWM/ADC等关键外设</td><td>必读</td></tr><tr><td>《Digital Control of Dynamic Systems》</td><td>Gene F. Franklin</td><td>数字控制理论经典，z变换、离散化、控制器设计</td><td>推荐</td></tr></tbody></table><h3 id="ups专题" tabindex="-1">UPS专题 <a class="header-anchor" href="#ups专题" aria-label="Permalink to &quot;UPS专题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>书名</th><th>作者</th><th>说明</th><th>优先级</th></tr></thead><tbody><tr><td>《UPS应用技术》</td><td>王其英</td><td>国内UPS领域权威著作，覆盖各类型UPS原理与设计</td><td>必读</td></tr><tr><td>《Uninterruptible Power Supplies and Active Filters》</td><td>Ali Emadi</td><td>英文UPS专著，含主动滤波与电能质量内容</td><td>参考</td></tr></tbody></table><h2 id="二、在线课程与教程" tabindex="-1">二、在线课程与教程 <a class="header-anchor" href="#二、在线课程与教程" aria-label="Permalink to &quot;二、在线课程与教程&quot;">​</a></h2><h3 id="系统性课程" tabindex="-1">系统性课程 <a class="header-anchor" href="#系统性课程" aria-label="Permalink to &quot;系统性课程&quot;">​</a></h3><ul><li><a href="https://www.icourse163.org/course/UESTC-1206862805" target="_blank" rel="noreferrer">电子科技大学《嵌入式系统及应用》</a> — 国家级一流课程，ARM+uC/OS-II</li><li>TI C2000 Academy — TI官方C2000培训体系，含电源控制实验</li><li><a href="https://www.ti.com/tool/TIDA-00779" target="_blank" rel="noreferrer">TI High-Voltage Interleaved PFC Reference Design</a> — PFC参考设计</li></ul><h3 id="技术博客与文章" tabindex="-1">技术博客与文章 <a class="header-anchor" href="#技术博客与文章" aria-label="Permalink to &quot;技术博客与文章&quot;">​</a></h3><ul><li><a href="https://blog.csdn.net/weixin_42561464/article/details/151686686" target="_blank" rel="noreferrer">三相三电平VIENNA整流器仿真设计与分析实战</a> — 维也纳整流器SVPWM详解</li><li><a href="https://blog.csdn.net/xiaoheshang_123/article/details/160713493" target="_blank" rel="noreferrer">基于Simulink的三相维也纳整流器功率因数校正</a> — 三电平SVPWM+中点平衡</li><li><a href="https://wenku.csdn.net/answer/8o2t4rbw18hb" target="_blank" rel="noreferrer">电赛UPS电源题解题思路</a> — 在线式UPS双变换架构详解</li><li><a href="https://ask.csdn.net/questions/9596306" target="_blank" rel="noreferrer">维也纳整流器与LLC谐振变换器本质区别</a> — 拓扑对比与工程误判分析</li></ul><h2 id="三、芯片厂商参考设计-工程级" tabindex="-1">三、芯片厂商参考设计（工程级） <a class="header-anchor" href="#三、芯片厂商参考设计-工程级" aria-label="Permalink to &quot;三、芯片厂商参考设计（工程级）&quot;">​</a></h2><h3 id="ti-德州仪器" tabindex="-1">TI（德州仪器） <a class="header-anchor" href="#ti-德州仪器" aria-label="Permalink to &quot;TI（德州仪器）&quot;">​</a></h3><ul><li><a href="https://www.ti.com/solution/single-phase-online-ups" target="_blank" rel="noreferrer">Single Phase Online UPS Block Diagram</a> — 单相在线式UPS系统框图与芯片选型</li><li>UCD3138 PFC Application Notes (SLUA708/SLUA712) — 数字PFC控制器固件设计</li><li>C2000 MCU系列 (TMS320F280039C/F28P650DK) — 电源控制专用MCU</li><li><a href="https://www.ti.com/product/TMS320F28075" target="_blank" rel="noreferrer">TMS320F28075 产品页</a> — TI 官方产品入口，确认 F28075 状态、参数、datasheet、TRM、errata 和软件资源</li><li><a href="https://www.ti.com/lit/ds/symlink/tms320f28075.pdf" target="_blank" rel="noreferrer">TMS320F2807x Real-Time Microcontrollers datasheet</a> — F28075/F2807x 数据手册，查芯片特性、封装、引脚、电气约束和外设数量</li><li><a href="https://www.ti.com/lit/pdf/spruhm9" target="_blank" rel="noreferrer">TMS320F2807x Technical Reference Manual</a> — F2807x 技术参考手册，查时钟、GPIO、PIE、ePWM、ADC、Trip Zone、通信和 CLA/DMA 等寄存器配置</li><li><a href="https://www.ti.com/tool/C2000WARE" target="_blank" rel="noreferrer">C2000Ware</a> — TI 官方 C2000 基础软件包，包含 device-specific drivers、libraries、peripheral examples、bit-field headers 和开发板资料</li><li><a href="https://www.ti.com/tool/C2000WARE-DIGITALPOWER-SDK" target="_blank" rel="noreferrer">C2000Ware DigitalPower SDK</a> — 面向 AC-DC、DC-DC、DC-AC 数字电源应用的软件、例程和 powerSUITE 工具，可作为 UPS/PCS 后续工程参考</li></ul><h3 id="st-意法半导体" tabindex="-1">ST（意法半导体） <a class="header-anchor" href="#st-意法半导体" aria-label="Permalink to &quot;ST（意法半导体）&quot;">​</a></h3><ul><li>STM32G4系列 — 高性能混合信号MCU，适合电源控制</li><li>STM32F334 — 内置高分辨率定时器（HRPWM），适合数字电源</li></ul><h3 id="infineon-英飞凌" tabindex="-1">Infineon（英飞凌） <a class="header-anchor" href="#infineon-英飞凌" aria-label="Permalink to &quot;Infineon（英飞凌）&quot;">​</a></h3><ul><li>XMC4000系列 — 工业级电源控制MCU</li><li>EiceDRIVER栅极驱动器 — UPS功率级驱动方案</li></ul><h2 id="四、仿真工具" tabindex="-1">四、仿真工具 <a class="header-anchor" href="#四、仿真工具" aria-label="Permalink to &quot;四、仿真工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>说明</th></tr></thead><tbody><tr><td>MATLAB/Simulink</td><td>系统级仿真</td><td>控制算法验证、SVPWM仿真、环路设计</td></tr><tr><td>PSIM</td><td>电力电子仿真</td><td>专为电力电子设计，仿真速度快</td></tr><tr><td>LTspice</td><td>电路级仿真</td><td>免费SPICE仿真，适合电路细节验证</td></tr><tr><td>PLECS</td><td>功率电子仿真</td><td>热模型+电气模型联合仿真</td></tr></tbody></table><h2 id="五、社区与论坛" tabindex="-1">五、社区与论坛 <a class="header-anchor" href="#五、社区与论坛" aria-label="Permalink to &quot;五、社区与论坛&quot;">​</a></h2><ul><li>21ic电子网论坛 — 国内电源技术讨论</li><li>电子发烧友论坛 — 电源/UPS版块</li><li>EEVblog Forum — 国际电子工程社区</li><li>TI E2E论坛 — TI芯片技术支持</li><li>知乎电力电子话题 — 中文技术讨论</li></ul><h2 id="六、标准与规范" tabindex="-1">六、标准与规范 <a class="header-anchor" href="#六、标准与规范" aria-label="Permalink to &quot;六、标准与规范&quot;">​</a></h2><ul><li>IEC 62040 — UPS国际标准</li><li>GB/T 7260 — 中国UPS国家标准</li><li>IEC 61000-3-2/3-12 — 谐波电流限值</li><li>IEEE 519 — 谐波控制标准</li></ul>',26)])])}const P=e(i,[["render",d]]);export{u as __pageData,P as default};
